import Timezone, {isoStringParser, TimezoneJSON} from '../location/Timezone';
import DateTimeUtils from './DateTimeUtils';

//Checks for values like 0d, 1w, 3m, 2y, and negatives like -2d
const relativeDayParser = /^(-?\d+)(d|wd|w|m|y)/i;

//checks for values that are just a number, like 12
const dateParser = /^(\d+)$/;

//checks for 'MM/DD', like 03/04 for march 4th
const monthDateParser = /^(\d?\d)[\/-](\d?\d)$/;

//checks for 'MM/DD/YYYY', like '03/04/2017' for march 4th, 2017
const fullDateParser = /^(\d\d)\/(\d\d)\/(\d\d\d\d)$/;

//checks for days, like 'wednesday', or 'tuesday_-1w'
//currently the rules only output "tuesday_-1w" from "last tuesday" but I will be handling
//more numbers than that just in case that changes
// end goal: /^(sunday|monday|...)(_[-+]?\dw)?$/i
const dayOfWeekParser = new RegExp('^(' + DateTimeUtils.DAYS_OF_WEEK.join('|') + ')(_[-+]?\\dw)?$', 'i');

//like the relativeDayParser, but pulls out just the number of weeks
const pastDOWParser = /^_([-+]?\d+)w$/;

//checks for names of months
const monthNameParser = new RegExp('^(' + DateTimeUtils.MONTHS.join('|') + ')$', 'i');

//checks for full years
const yearParser = /^(\d{4})$/;
const DAY_IN_MS = 24*60*60*1000; // hours*minutes*seconds*milliseconds
const HOUR_IN_MS = 60*60*1000; // minutes*seconds*milliseconds

//parses values like 3:00, or 10:00PM
const timeParser = /(\d+):(\d\d)(AM|PM)*/;

//relative time parser, values like 3h0m0s or 0h20m5s, from nlu results "3 hours from now" or "20 minutes from now"
const relativeTimeParser = /^(-?)(\d+)h(\d+)m(\d+)s$/;

//utility function - pad the left side of a string with 0s to hit a specified length
function pad(input:string|number, length: number):string {
    if (typeof input === 'number') {
        input = input.toString();
    }
    while(input.length < length) {
        input = '0' + input;
    }
    return input;
}

export enum timePeriods {
    YEAR = 'year',
    MONTH = 'month',
    WEEK = 'week',
    WEEKEND = 'weekend',
    DAY = 'day',
    MORNING = 'morning',
    AFTERNOON = 'afternoon',
    EVENING = 'evening',
    NIGHT = 'night',
    HOUR = 'hour',
    MINUTE = 'minute',
    NOW = 'now'
}

/**
 * @interface jibo.utils~ToStringOptions
 * @description Options to be used when handling the string conversion of dates and times.
 * @prop {boolean} [suppressVerbalOutput] If the `DateTime` should return
 *        an empty string for [toString()]{@link jibo.utils.DateTime#toString} and [prefixOnAt()]{@link jibo.utils.DateTime#prefixOnAt}.
 *        Allows greater control over how MIMs use the `DateTime` without the skill having to handle things
 *        specially.
 * @prop {boolean} [dropPeriod] If the period (AM/PM) should be dropped from the time. Has no effect if the time would not
 *       be output.
 * @prop {boolean} [display] `true` if the output should be display-compatible. Generally [toString()]{@link jibo.utils.DateTime#toString}
 *       should output display friendly strings, but some options may change that. To ensure that you get a
 *       display-compatible string, use this option.
 * @prop {boolean} [prefixOnAt] Prefixes most days with 'On' and most times with 'at'.
 *       Examples: "On Tuesday", "At 3:00PM", "Tomorrow", "This morning".
 *       This replaces the use of [prefixOnAt()]{@link jibo.utils.DateTime#prefixOnAt}.
 * @prop {boolean} [timeOnly] If only the time should be output, even if the date is not the
 *       current date.
 * @prop {boolean} [dateOnly] If only the date/day should be output, even if it is the current day.
 */
export interface ToStringOptions {
    suppressVerbalOutput?:boolean;
    dropPeriod?:boolean;
    display?:boolean;
    prefixOnAt?:boolean;
    timeOnly?:boolean;
    dateOnly?:boolean;
    weeHoursAreTonight?:boolean;
}

/**
 * @interface jibo.utils~LocalTime
 * @prop {number} year YYYY
 * @prop {string} month Full month name (i.e. `January`, `February`, ...)
 * @prop {number} monthNum 0-11
 * @prop {string} dayOfWeek Full weekday name (i.e. `Monday`, `Tuesday`, ...)
 * @prop {number} date 1-31
 * @prop {number} hour 0-23
 * @prop {number} minute 0-59
 * @prop {number} seconds 0-59
 * @prop {number} milliseconds 0-999
 */
export interface LocalTime {
    year: number;
    month: string;
    monthNum: number;
    dayOfWeek: string;
    date: number;
    hour: number;//24 hour time
    minute: number;
    seconds: number;
    milliseconds: number;
}

/**
 * Interface describing the serialized form of a [DateTime]{@link jibo.utils.DateTime} instance.
 * @interface jibo.utils~DateTimeJSON
 * @prop {'DateTime'} _type Internal type field (for serializing and de-serializing).
 * @prop {number} utc Milliseconds elapsed since January 1st 1970 UTC, like `Date.now()`.
 * @prop {jibo.utils~TimezoneJSON} timezone Serialized form of [timezone]{@link jibo.utils.Timezone}.
 * @prop {number} durationDays Duration of a time period in days, referring to weeks or weekends. Mutually exclusive with other durations.
 * @prop {number} durationHours Duration of a time period in hours, referring to morning, afternoon, evening, or night.
 * @prop {number} durationMinutes Duration of a time period in minutes, currently not used.
 * @prop {string} timePeriod The original time period referenced by the input - a value from the [timePeriods]{@link jibo.utils.DateTime#timePeriods} enum.
 */
export interface DateTimeJSON {
    __type: 'DateTime';
    utc: number;
    timezone: TimezoneJSON;
    durationDays: number;
    durationHours: number;
    durationMinutes: number;
    timePeriod: string;
}

/**
 * Class for handling locations - taking NLU inputs and turning them into full locations with
 * a latitude and longitude, and optionally an attached timezone.
 * @class DateTime
 * @memberof jibo.utils
 * @param {string|Date|jibo.utils.Timezone} input Input from the NLU date/time factory.
 * @param {Function} [input.getTime()] Required if `input` type = `Date`
 * @param {jibo.utils.Timezone} [input.timezone] Required if `input` type = `DateTime`.
 * @param {number} [input.durationDays] Required if `input` type = `DateTime`.
 * @param {number} [input.durationHours] Required if `input` type = `DateTime`.
 * @param {number} [input.durationMinutes] Required if `input` type = `DateTime`.
 * @param {number} [input.timePeriod] Required if `input` type = `DateTime`.
 * @param {String|jibo.utils.Timezone} nluTime Input from the NLU date/time factory
 * @param {jibo.utils.Timezone} timezone Timezone that this date is in.
 */
class DateTime {
    /**
     * Duration of a time period in days, referring to weeks or weekends. Mutually exclusive
     * with other durations.
     * @name jibo.utils.DateTime#durationDays
     * @type {Number}
     * @readOnly
     */
    public durationDays:number;
    /**
     * Duration of a time period in hours, referring to morning, afternoon, evening, or night.
     * @name jibo.utils.DateTime#durationHours
     * @type {Number}
     * @readOnly
     */
    public durationHours:number;
    /**
     * Duration of a time period in minutes, currently not used.
     * @name jibo.utils.DateTime#durationMinutes
     * @type {Number}
     * @readOnly
     */
    public durationMinutes:number;
    /**
     * The original time period referenced by the input - a value from the [timePeriods]{@link jibo.utils.DateTime#timePeriods} enum.
     * These values affect how the `DateTime` is converted into a string.
     * @name jibo.utils.DateTime#timePeriod
     * @type {String}
     * @readOnly
     */
    public timePeriod:string;
    /**
     * Private utc value. The public version is a setter that also clears _localTime.
     * @name jibo.utils.DateTime#_utc
     * @type {Number}
     * @private
     */
    private _utc:number;
    /**
     * Private timezone value. The public version is a setter that also clears _localTime.
     * @name jibo.utils.DateTime#_timezone
     * @type {Timezone}
     * @private
     */
    private _timezone:Timezone;
    /**
     * Cached LocalTime to prevent having to recreate that data as often.
     * @name jibo.utils.DateTime#_localTime
     * @type {Object}
     * @private
     */
    private _localTime:LocalTime;

    /**
     * Enum of the time periods.
     * @name jibo.utils.DateTime#timePeriods
     * @type {Object}
     * @static
     * @prop YEAR
     * @prop MONTH
     * @prop WEEK
     * @prop WEEKEND
     * @prop DAY
     * @prop MORNING
     * @prop AFTERNOON
     * @prop EVENING
     * @prop NIGHT
     * @prop HOUR
     * @prop MINUTE
     * @prop NOW
     */
    public static get timePeriods() { return timePeriods; }

    /**
     * @method jibo.utils.DateTime#constructor
     * @param {String} nluDay Input from the NLU date/time factory.
     * @param {String} nluTime Input from the NLU date/time factory.
     * @param {jibo.utils.Timezone} timezone Timezone that this date is in.
     */
    constructor(nluDay?: string, nluTime?: string, timezone?: Timezone);
    /**
     * @method jibo.utils.DateTime#constructor
     * @param {Object} serializedDateTime An object from [toJSON()]{@link jibo.utils.DateTime#toJSON} to deserialize.
     */
    constructor(serializedDateTime:any);
    /**
     * @method jibo.utils.DateTime#constructor
     * @param {Number} epochTime Milliseconds elapsed since January 1st 1970 UTC, like `Date.now()`.
     * @param {jibo.utils.Timezone} timezone Timezone that this date is in.
     */
    constructor(epochTime:number, timezone?:Timezone);
    /**
     * @method jibo.utils.DateTime#constructor
     * @param {Date} date A standard Date object.
     * @param {jibo.utils.Timezone} timezone Timezone that this date is in.
     */
    constructor(date:Date, timezone?:Timezone);
    constructor(input?:string|any, nluTime?:string|Timezone, timezone?:Timezone) {
        if (nluTime instanceof Timezone) {
            timezone = nluTime;
            nluTime = null;
        }
        this.utc = NaN;
        this.timezone = null;
        this.durationDays = 0;
        this.durationHours = 0;
        this.durationMinutes = 0;
        this.timePeriod = null;
        this._localTime = null;
        //actually handle our input now
        if (typeof input === 'string' && isoStringParser.test(input)) {
            //if ISO string, handle that by getting UTC time
            //if no timezone supplied, make one to match the iso string
            if (!timezone) {
                timezone = Timezone.fromISOString(input);
            }
            input = new Date(input).getTime();
        }
        else if (input instanceof Date) {
            //if passed a date, all we care about is the epoch time, so fetch that
            //then the normal number input can catch it
            input = input.getTime();
        }
        if (typeof input === 'number') {
            this.utc = input;
            this.timezone = timezone || new Timezone();
            this.timePeriod = timePeriods.MINUTE;
        }
        else if (input && input.__type === 'DateTime') {
            this.utc = input.utc;
            this.timezone = new Timezone(input.timezone);
            this.durationDays = input.durationDays;
            this.durationHours = input.durationHours;
            this.durationMinutes = input.durationMinutes;
            this.timePeriod = input.timePeriod;
        } else if (input || nluTime || timezone) {
            this.timezone = timezone || new Timezone();
            this._parseInput(input, nluTime);
        } else {
            this.timezone = new Timezone();
            this._parseInput(input, nluTime);
        }
        //TODO - allow other types of input, so that Weather can set up `DateTimes` for hours or days
        //within time periods for weather
    }

    /**
     * Time in UTC. If this `DateTime` represents a period of time, then UTC is the start of it.
     * @name jibo.utils.DateTime#utc
     * @type {Number}
     */
    public get utc():number {
        return this._utc;
    }
    public set utc(value:number) {
        this._utc = value;
        this._localTime = null;
    }

    /**
     * The Timezone object that is the timezone that this `DateTime` exists in.
     * @name jibo.utils.DateTime#timezone
     * @type {jibo.utils.Timezone}
     */
    public get timezone():Timezone {
        return this._timezone;
    }
    public set timezone(value:Timezone) {
        this._timezone = value;
        this._localTime = null;
    }

    /**
     * Makes a copy of this `DateTime`, including a copy of the Timezone
     * @method jibo.utils.DateTime#clone
     * @return {DateTime} The `DateTime` clone.
     */
    clone() {
        return new DateTime(this.toJSON());
    }

    /**
     * Changes this `DateTime` to the next section of the day - morning, afternoon, evening, night.
     * @method jibo.utils.DateTime#jumpToNextDayPeriod
     */
    jumpToNextDayPeriod() {
        let date = new Date(this.utc + this.timezone.offsetUTC);
        let hours = date.getUTCHours();
        //setting time has extra 0s to remove minutes, seconds, milliseconds
        if (hours < 6) {
            //morning: 6-11AM, inclusive
            date.setUTCHours(6, 0, 0, 0);
            this.durationHours = 5;
            this.timePeriod = timePeriods.MORNING;
        } else if (hours < 12) {
            //afternoon: 12-5PM, inclusive
            date.setUTCHours(12, 0, 0, 0);
            this.durationHours = 6;
            this.timePeriod = timePeriods.AFTERNOON;
        } else if (hours < 18) {
            //evening: 6-9PM, inclusive
            date.setUTCHours(18, 0, 0, 0);
            this.durationHours = 4;
            this.timePeriod = timePeriods.EVENING;
        } else if (hours < 22) {
            //night: 10PM-4AM, inclusive
            date.setUTCHours(22, 0, 0, 0);
            this.durationHours = 7;
            this.timePeriod = timePeriods.NIGHT;
        } else {
            //is 10PM to midnight, go to next morning
            date.setUTCDate(date.getUTCDate() + 1);
            date.setUTCHours(6, 0, 0, 0);
        }
        this.utc = date.getTime() - this.timezone.offsetUTC;
    }

    /**
     * Adds a set number of years to the `DateTime`.
     * @method jibo.utils.DateTime#addYear
     * @param {Number} [years=1] The number of years to add.
     */
    addYear(years:number = 1) {
        let date = new Date(this.utc + this.timezone.offsetUTC);
        date.setUTCFullYear(date.getUTCFullYear() + years);
        this.utc = date.getTime() - this.timezone.offsetUTC;
    }

    /**
     * Adds a set number of days to the `DateTime` and changes it to a `DAY` time period.
     * @method jibo.utils.DateTime#addDays
     * @param  {Number} days The number of days to add.
     * @param {boolean} [zeroHours=false] If `true` will set hours/minutes/seconds to `0`.
     */
    addDays(days:number, zeroHours = false) {
        let date = new Date(this.utc + this.timezone.offsetUTC);
        date.setUTCDate(date.getUTCDate() + days);
        if (zeroHours) {
            date.setUTCHours(0, 0, 0, 0);
            this.timePeriod = timePeriods.DAY;
        }
        this.utc = date.getTime() - this.timezone.offsetUTC;
    }

    /**
     * Adds a set number of hours to the `DateTime` and changes to an `HOUR` time period
     * @method jibo.utils.DateTime#addHours
     * @param  {Number} hours The number of hours to add.
     * @param {boolean} [zeroMinutes=false] If `true` will set minutes/seconds to `0`.
     */
    addHours(hours:number, zeroMinutes = false) {
        let date = new Date(this.utc + this.timezone.offsetUTC);
        date.setUTCHours(date.getUTCHours() + hours);
        if (zeroMinutes) {
            date.setUTCMinutes(0, 0, 0);
            this.timePeriod = timePeriods.HOUR;
        }
        this.utc = date.getTime() - this.timezone.offsetUTC;
    }

    /**
     * Sets the local time, with hours being in 24 hour time (0-23).
     * Changes to an `HOUR` time period if no minutes were provided,
     * or `MINUTE` time period if they were.
     * @method jibo.utils.DateTime#setTime
     * @param  {number} hours Hour in 24 hour time to set the time to.
     * @param  {number} [minutes=0] Minutes to set the time to.
     * @param  {number} [seconds=0] Seconds to set the time to.
     * @param  {number} [milliseconds=0] milliseconds to set the time to.
     */
    setTime(hours:number, minutes:number, seconds:number=0, milliseconds:number=0) {
        let date = new Date(this.utc + this.timezone.offsetUTC);
        date.setUTCHours(hours, minutes || 0, seconds, milliseconds);
        this.utc = date.getTime() - this.timezone.offsetUTC;
        if (minutes !== undefined) {
            this.timePeriod = timePeriods.MINUTE;
        } else {
            this.timePeriod = timePeriods.HOUR;
        }
    }

    /**
     * Irreversibly remove the time from this `DateTime`, turning it into just a full day.
     * This has no effect on `DateTimes` that are already days, weekends, weeks, months, or years.
     * @method jibo.utils.DateTime#stripTime
     */
    stripTime() {
        let timePeriod = this.timePeriod;
        if (timePeriod === timePeriods.HOUR || timePeriod === timePeriods.MINUTE ||
            timePeriod === timePeriods.MORNING || timePeriod === timePeriods.AFTERNOON ||
            timePeriod === timePeriods.EVENING || timePeriod === timePeriods.NIGHT ||
            timePeriod === timePeriods.NOW) {
            this.timePeriod = timePeriods.DAY;
            let date = new Date(this.utc + this.timezone.offsetUTC);
            date.setUTCHours(0, 0, 0, 0);
            this.utc = date.getTime() - this.timezone.offsetUTC;
            this.durationHours = this.durationMinutes = 0;
        }
    }

    /**
     * If this `DateTime` is in the past. Time periods are only in the past if the end of the period
     * is in the past.
     * @method jibo.utils.DateTime#isPast
     * @return {Boolean} If the time period has ended and is thus fully in the past.
     */
    public isPast():boolean {
        let endTime:number = this._utc;

        if (this.timePeriod === timePeriods.YEAR) {
            const endDate = new Date(endTime);
            endDate.setUTCFullYear(endDate.getUTCFullYear() + 1);
            endTime = endDate.getTime();
        }
        else if (this.timePeriod === timePeriods.MONTH) {
            const endDate = new Date(endTime);
            endDate.setUTCMonth(endDate.getUTCMonth() + 1);
            endTime = endDate.getTime();
        } else if (this.timePeriod === timePeriods.DAY) {
            const endDate = new Date(endTime);
            endDate.setUTCDate(endDate.getUTCDate() + 1);
            endTime = endDate.getTime();
        }
        if (this.durationDays) {
            endTime += this.durationDays * DAY_IN_MS;
        }
        if (this.durationHours) {
            endTime += this.durationHours * HOUR_IN_MS;
        }
        if (this.durationMinutes) {
            endTime += this.durationMinutes * 60 * 1000;
        }

        return endTime < Date.now();
    }

    /**
     * If this `DateTime` is in the future (by any amount).
     * @method jibo.utils.DateTime#isFuture
     * @return {Boolean} If the time has not come to pass yet.
     */
    public isFuture():boolean {
        return this._utc > Date.now();
    }

    /**
     * If this `DateTime` is within the specified date range
     * @method jibo.utils.DateTime#isInRange
     * @param {string} startDate The start date, in the format 'M/D' or 'M-D'
     * @param {string} endDate The end date, in the format 'M/D' or 'M-D'
     * @return {Boolean} If the time has not come to pass yet.
     */
    public isInRange(startDate:string, endDate:string):boolean {
        try {
            const start = monthDateParser.exec(startDate);
            const end = monthDateParser.exec(endDate);
            const startMonth = parseInt(start[1]) - 1;//convert month to 0-11
            const startDay = parseInt(start[2]);
            const endMonth = parseInt(end[1]) - 1;//convert month to 0-11
            const endDay = parseInt(end[2]);
            const {monthNum, date} = this.getLocalTime();
            //if range wraps around a year border
            if (endMonth < startMonth || (endMonth === startMonth && endDay < startDay)) {
                //if between the month range in the wrong direction, return false
                if (startMonth > monthNum && endMonth < monthNum) {
                    return false;
                }
                //need to handle wrapped ranges with the same starting and ending month
                if (startMonth === endMonth && monthNum === startMonth &&
                    (date > startDay || date < endDay)) {
                    return true;
                }
                //if past the range within an edge month, return false
                if ((monthNum === startMonth && date < startDay) ||
                    (monthNum === endMonth && date > endDay)) {
                    return false;
                }
                //at this point, we have to be in the range
                return true;
            } else {
                //if outside the month range, return false
                if (monthNum < startMonth || monthNum > endMonth) {
                    return false;
                }
                //if outside the range within an edge month, return false
                if ((monthNum === startMonth && date < startDay) ||
                    (monthNum === endMonth && date > endDay)) {
                    return false;
                }
                //at this point, we have to be in the range
                return true;
            }
        } catch (e) {
            console.error(e);
            return false;
        }
    }

    /**
     * Returns an object with separate properties for local time (in this `DateTime`'s timezone)
     * If this `DateTime` refers to a time period, then the local time will be the start time of that
     * time period
     * @method jibo.utils.DateTime#getLocalTime
     * @return {Object} The local time object.
     */
    getLocalTime() {
        if (!this._localTime) {
            const localDate = new Date(this.utc + this.timezone.offsetUTC);
            const month = localDate.getUTCMonth();
            this._localTime = {
                year: localDate.getUTCFullYear(),
                month: DateTimeUtils.MONTHS[month],
                monthNum: month,
                dayOfWeek: DateTimeUtils.DAYS_OF_WEEK[localDate.getUTCDay()],
                date: localDate.getUTCDate(),
                hour: localDate.getUTCHours(),//24 hour time
                minute: localDate.getUTCMinutes(),
                seconds: localDate.getUTCSeconds(),
                milliseconds: localDate.getUTCMilliseconds()
            };
        }
        return this._localTime;
    }

    /**
     * Gets this date in `MMDD` format, useful for some web APIs.
     * @method jibo.utils.DateTime#getLocalMMDD
     * @return {String} The date.
     */
    getLocalMMDD() {
        let rtn = '';
        let date = new Date(this.utc + this.timezone.offsetUTC);
        let month = date.getUTCMonth() + 1;//month is 0 based
        rtn += month < 10 ? '0' + month : month;
        let day = date.getUTCDate();
        rtn += day < 10 ? '0' + day : day;
        return rtn;
    }

    /**
     * Gets this date in `YYYYMMDD` format, useful for some web APIs.
     * @method jibo.utils.DateTime#getLocalYYYYMMDD
     * @return {String} The date.
     */
    getLocalYYYYMMDD() {
        let rtn = '';
        let date = new Date(this.utc + this.timezone.offsetUTC);
        rtn += date.getUTCFullYear();
        let month = date.getUTCMonth() + 1;//month is 0 based
        rtn += month < 10 ? '0' + month : month;
        let day = date.getUTCDate();
        rtn += day < 10 ? '0' + day : day;
        return rtn;
    }

    //TODO: test how this handles past dates - weather needs to be able to handle partially past time periods
    //used by weather to accurately get forecasting regardless of location
    /**
     * Returns the number of days between this date and the current date.
     * @method jibo.utils.DateTime#getRelativeDays
     * @return {Number} The number of days.
     */
    getRelativeDays() {
        // Discard the time information.
        let thisDate = new Date(this.utc + this.timezone.offsetUTC);
        let utc1 = Date.UTC(thisDate.getUTCFullYear(), thisDate.getUTCMonth(), thisDate.getUTCDate());
        let now = new Date(Date.now() + this.timezone.offsetUTC);
        let utc2 = Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate());

        //adding 0.1 because I am afraid of floating point errors combined with Math.floor()
        return Math.floor((utc1 - utc2) / DAY_IN_MS + 0.1);
    }

    //TODO: test how this handles past dates - weather needs to be able to handle partially past time periods
    //used by weather to accurately get forecasting regardless of location
    /**
     * Returns the number of hours between this date/time and the current time.
     * @method jibo.utils.DateTime#getRelativeHours
     * @return {Number} The number of hours.
     */
    getRelativeHours() {
        // Discard time information beyond hours.
        let thisDate = new Date(this.utc + this.timezone.offsetUTC);
        let utc1 = Date.UTC(thisDate.getUTCFullYear(), thisDate.getUTCMonth(), thisDate.getUTCDate(), thisDate.getUTCHours());
        let now = new Date(Date.now() + this.timezone.offsetUTC);
        let utc2 = Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate(), now.getUTCHours());

        //adding 0.1 because I am afraid of floating point errors combined with Math.floor()
        return Math.floor((utc1 - utc2) / HOUR_IN_MS + 0.1);
    }

    /**
     * Gets the local date/time (in this DateTime's timezone) as a human readable or Jibo speakable
     * string.
     * It is designed to output stuff like "Today", "3:00PM", "Tomorrow at 3:30PM", "Tuesday".
     * If [ToStringOptions.suppressVerbalOutput]{@link jibo.utils~ToStringOptions} is `true`, then it returns an empty string.
     * @method jibo.utils.DateTime#toString
     * @param {jibo.utils~ToStringOptions} [options] Options to be used when handling the string conversion.
     * @return {String} The verbal output.
     */
    toString(options?:ToStringOptions) {
        if (!options) {
            options = {};
        }
        if (options.suppressVerbalOutput) {
            return '';
        }
        let rtn = '';
        let thisDate = new Date(this.utc + this.timezone.offsetUTC);
        let relativeDays = this.getRelativeDays();
        //handle the long time periods, because they exist. Most use cases will probably
        //not be using them as output, as they would generally be an input to narrow down intent
        //Current implementation is that they override/ignore other settings
        let timePeriod = this.timePeriod;
        //track if we use the long time period stuff so that we can skip later
        let wasLongPeriod = false;
        // region long date periods
        if (timePeriod === timePeriods.YEAR || timePeriod === timePeriods.MONTH ||
            timePeriod === timePeriods.WEEK || timePeriod === timePeriods.WEEKEND) {
            wasLongPeriod = true;
            let targetWeek, nowWeek, daysDiff, weeksDiff;
            switch (this.timePeriod) {
                case timePeriods.YEAR:
                    //just use the year - figuring out 'this year', 'last year', 'next year', and
                    //then also handling stuff outside those values would be a pain
                    rtn = String(thisDate.getUTCFullYear());
                    break;
                case timePeriods.MONTH:
                    //just use the year - figuring out 'this year', 'last year', 'next year', and
                    //then also handling stuff outside those values would be a pain
                    rtn = DateTimeUtils.MONTHS[thisDate.getUTCMonth()];
                    break;
                case timePeriods.WEEK:
                    //compare days between mondays
                    targetWeek = new Date(this.utc + this.timezone.offsetUTC);
                    targetWeek.setUTCDate(targetWeek.getUTCDate() - targetWeek.getUTCDay() + 1);
                    nowWeek = new Date(Date.now() + this.timezone.offsetUTC);
                    nowWeek.setUTCDate(nowWeek.getUTCDate() - nowWeek.getUTCDay() + 1);
                    daysDiff = DateTimeUtils.getDaysBetweenDates(nowWeek, targetWeek);
                    weeksDiff = Math.round(daysDiff / 7);//should be an int at this point
                    if (weeksDiff === 0) {
                        rtn = 'this week';
                    } else if (weeksDiff > 0) {
                        if (weeksDiff === 1) {
                            rtn = 'next week';
                        } else {
                            rtn = weeksDiff + ' weeks from now';
                        }
                    } else {
                        //weeks is negative here
                        if (weeksDiff === -1) {
                            rtn = 'last week';
                        } else {
                            rtn = Math.abs(weeksDiff) + ' weeks ago';
                        }
                    }
                    break;
                case timePeriods.WEEKEND:
                    //compare days between saturdays
                    targetWeek = new Date(this.utc + this.timezone.offsetUTC);
                    targetWeek.setUTCDate(targetWeek.getUTCDate() - targetWeek.getUTCDay() + 6);
                    nowWeek = new Date(Date.now() + this.timezone.offsetUTC);
                    nowWeek.setUTCDate(nowWeek.getUTCDate() - nowWeek.getUTCDay() + 6);
                    daysDiff = DateTimeUtils.getDaysBetweenDates(nowWeek, targetWeek);
                    weeksDiff = Math.round(daysDiff / 7);//should be an int at this point
                    if (weeksDiff === 0) {
                        rtn = 'this weekend';
                    } else if (weeksDiff > 0) {
                        if (weeksDiff === 1) {
                            rtn = 'next weekend';
                        } else {
                            rtn = weeksDiff + ' weekends from now';
                        }
                    } else {
                        //weeks is negative here
                        if (weeksDiff === -1) {
                            rtn = 'last weekend';
                        } else {
                            rtn = Math.abs(weeksDiff) + ' weekends ago';
                        }
                    }
                    break;
            }
        }
        // endregion long date periods
        //if the day output was a date
        let usedDate = false;
        if (!wasLongPeriod && !options.timeOnly) {
            // region day calculation
            //if the timePeriod refers to a whole day or we aren't talking about a time today,
            //then we need to have the day present
            if (timePeriod === timePeriods.DAY || relativeDays !== 0 || options.dateOnly || options.weeHoursAreTonight) {
                let now = new Date(Date.now() + this.timezone.offsetUTC).getUTCHours();
                let thisDateHours =  thisDate.getUTCHours();
                if (relativeDays === 0) {
                    if (!options.weeHoursAreTonight) {
                        rtn = 'today';
                    //thisDate considered "tonight" if thisDate is before 3am and current time is between 12am and thisDate
                    //or if current time is between 6am and thisDate and thisDate is after 8pm
                    } else if (now < thisDateHours && ((thisDateHours < 3) || (now >= 6 && thisDateHours >= 20))) {
                        rtn = 'tonight';
                    }
                } else if (relativeDays === -1) {
                    rtn = 'yesterday';
                } else if (relativeDays === 1) {
                    //thisDate considered "tomorrow" if "weeHoursAreTonight" boolean is false or if thisDate is after 3am
                    if (!options.weeHoursAreTonight || thisDateHours > 3) {
                        rtn = 'tomorrow';
                    //thisDate is "tonight" if "weeHoursAreTonight" boolean is true and thisDate is before 3 and current Time is after 6am
                    } else if (now > 6) {
                        rtn = 'tonight';
                    }
                } else if (relativeDays < 7 && relativeDays > 0) {
                    //day of week
                    rtn = DateTimeUtils.DAYS_OF_WEEK[thisDate.getUTCDay()];
                } else {
                    //anything farther uses a date, like 'March 4th'
                    usedDate = true;
                    rtn = DateTimeUtils.MONTHS[thisDate.getUTCMonth()];
                    rtn += ' ' + DateTimeUtils.getOrdinal(thisDate.getUTCDate());
                    let now = new Date(Date.now() + this.timezone.offsetUTC);
                    if (now.getUTCFullYear() !== thisDate.getUTCFullYear()) {
                        rtn += ' ' + thisDate.getUTCFullYear();
                    }
                }
            }
            // endregion day calculation
        }

        if (!wasLongPeriod && !options.dateOnly) {
            // region time periods
            //standard day time periods!
            if (timePeriod === timePeriods.MORNING) {
                if (usedDate) {
                    rtn = 'morning of ' + rtn;
                } else if (relativeDays === 0) {
                    rtn = 'this morning';
                } else {
                    rtn += ' morning'; //'yesterday morning', 'tomorrow morning', 'tuesday morning'
                }
            } else if (timePeriod === timePeriods.AFTERNOON) {
                if (usedDate) {
                    rtn = 'afternoon of ' + rtn;
                } else if (relativeDays === 0) {
                    rtn = 'this afternoon';
                } else {
                    rtn += ' afternoon'; //'yesterday afternoon', 'tuesday afternoon', etc
                }
            } else if (timePeriod === timePeriods.EVENING) {
                if (usedDate) {
                    rtn = 'evening of ' + rtn;
                } else if (relativeDays === 0) {
                    rtn = 'this evening';
                } else {
                    rtn += ' evening'; //'yesterday evening', 'tuesday evening', etc
                }
            } else if (timePeriod === timePeriods.NIGHT) {
                if (usedDate) {
                    rtn = 'night of ' + rtn;
                } else if (relativeDays === 0) {
                    rtn = 'tonight';
                } else if (relativeDays === -1) {
                    rtn = 'last night';
                } else {
                    rtn += ' night'; //'tomorrow night', 'tuesday night', etc
                }
            }
            // endregion time periods

            // region specific times
            if (timePeriod === timePeriods.HOUR || timePeriod === timePeriods.MINUTE || timePeriod === timePeriods.NOW) {
                //if it isn't the time alone, then use 'at' to separate day and time
                if (rtn) {
                    rtn += ' at ';
                }
                if (options.display) {
                    rtn += DateTimeUtils.getVisualTime(thisDate.getUTCHours(), thisDate.getUTCMinutes(), options.dropPeriod);
                }
                else {
                    rtn += DateTimeUtils.getVerbalTime(thisDate.getUTCHours(), thisDate.getUTCMinutes(), options.dropPeriod);
                }
            }
            // endregion specific times
        }

        // region prefixOnAt
        if (options.prefixOnAt) {
            //use relativeDays and the time period to determine what sort of prefix should be
            //used for the string
            //years and months get to be 'in 2016' and 'in march'
            if (timePeriod === timePeriods.YEAR || timePeriod === timePeriods.MONTH) {
                rtn = 'in ' + rtn;
            }
            //relative weeks and weekends are dumb and feel imprecise outside of this/next, and
            //get to be used as is
            else if (timePeriod === timePeriods.WEEK || timePeriod === timePeriods.WEEKEND) {
                //no effect
            }
            //times depend on the day - time alone for today is 'at 3:00PM',
            //others are 'on tuesday at 3:00PM' - yesterday and tomorrow get no prefix
            else if (!options.dateOnly &&
                (timePeriod === timePeriods.HOUR || timePeriod === timePeriods.MINUTE ||
                timePeriod === timePeriods.NOW || options.timeOnly)) {
                if (relativeDays === 0 || options.timeOnly) {
                    rtn = 'at ' + rtn;
                }
                else if (relativeDays === -1 || relativeDays === 1) {
                    //no effect
                } else {
                    rtn = 'on ' + rtn;
                }
            }
            //today, tomorrow, yesterday, this <evening|afternoon|morning>, tonight all go as is
            else if (relativeDays === 0 || relativeDays === -1 || relativeDays === 1) {
                //no effect
            } else {
                //all that's left is days and dates - tuesday, march 4th, etc
                rtn = 'on ' + rtn;
            }
        }
        // endregion prefixOnAt

        return rtn;
    }

    /**
     * @method jibo.utils.DateTime#prefixOnAt
     * @deprecated
     * @see jibo.utils~ToStringOptions
     */
    prefixOnAt(options?:ToStringOptions) {
        if (!options) {
            options = {};
        }
        options.prefixOnAt = true;
        return this.toString(options);
    }

    /**
     * Gets the relative time in a similar style to MomentJS, but simplified for display on Jibo's
     * screen.
     * Currently only supports past times.
     * @method jibo.utils.DateTime#toMoment
     * @return {String} The relative time output.
     */
    toMoment():string {
        if (Date.now() - this._utc < 0) {
            return 'The Future';
        }
        const diffInMin = (Date.now() - this._utc) / (1000 * 60);
        // < 30 minutes ago = Just Now
        if (diffInMin <= 30) {
            return 'Just Now';
        }
        // 30-60 minutes ago = Xm ago
        if (diffInMin <= 60) {
            return `${Math.floor(diffInMin)}m ago`;
        }
        // 1-24 hours ago = Xh ago
        const diffInHours = diffInMin / 60;
        if (diffInHours <= 24) {
            return `${Math.floor(diffInHours)}h ago`;
        }
        const relativeDays = -this.getRelativeDays();
        //1 day ago = Yesterday
        //2-7 days ago = Xd ago
        if (relativeDays <= 7) {
            return relativeDays === 1 ? 'Yesterday' : `${relativeDays}d ago`;
        }
        //older than that:
        //this year = Mon. Date (Oct 31st)
        //not this year = Mon. Date Year (Oct 31 2015)
        const local = this.getLocalTime();
        const now = new DateTime(Date.now(), this._timezone).getLocalTime();
        let date = DateTimeUtils.MONTH_ABBREVIATIONS[local.monthNum] + ' ';
        if (local.year === now.year) {
            date += DateTimeUtils.getOrdinal(local.date);
        } else {
            date += local.date + ' ' + local.year;
        }
        return date;
    }

    /**
     * Serializes the `DateTime` into a JSON object with markers to assist in deserialization.
     * @method jibo.utils.DateTime#toJSON
     * @return {jibo.utils~DateTimeJSON} The serialized `DateTime`.
     */
    toJSON():DateTimeJSON {
        return {
            __type: 'DateTime',
            utc: this.utc,
            timezone: this.timezone.toJSON(),
            durationDays: this.durationDays,
            durationHours: this.durationHours,
            durationMinutes: this.durationMinutes,
            timePeriod: this.timePeriod
        };
    }

    /**
     * Outputs an ISO formatted string. See
     * [MDN web docs](https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/Date/toISOString)
     * @method jibo.utils.DateTime#toISOString
     * @return {string}
     */
    toISOString():string {
        const local = this.getLocalTime();
        //YYYY-MM-DDTHH:mm:ss.sss
        return `${pad(local.year, 4)}-${pad((local.monthNum + 1), 2)}-${pad(local.date, 2)}T${pad(local.hour, 2)}:${pad(local.minute, 2)}:${pad(local.seconds, 2)}.${pad(local.milliseconds, 3)}` + this._timezone.toISOString();
    }

    /**
     * To be called by logging methods to have a more useful output.
     * MIMs will call this if it is in the MIM prompt data.
     * @method jibo.utils.DateTime#toLog
     */
    toLog() {
        return this.toJSON();
    }

    /**
     * Parses date and time data output by the NLU parser.
     * @method jibo.utils.DateTime#_parseInput
     * @param  {String} nluDate Date output by the NLU date factory.
     * @param  {String} nluTime Time output by the NLU time factory.
     * @private
     */
    private _parseInput(nluDate, nluTime) {
        //nlu rules output a string of 'null' when there is nothing
        if (nluDate === 'null') {
            nluDate = null;
        }
        if (nluTime === 'null') {
            nluTime = null;
        }
        let dateUTC:Date = null;
        //This function deals entirely with the UTC functions of the Date class - the Date that it
        //creates has been offset by the timezone such that the UTC time of the Date is actually
        //local time in the target timezone, not UTC.
        //Once the date & time has been calculated, the actual UTC time will be retrieved.
        // region date-parsing
        /* ==============
            DATE PARSING
           ==============*/
        //keep track of if we are referring to today, for the purposes of better time calculation
        let dayNotSpecified = false;
        let isToday = false;
        if (!nluDate) {
            //set dateUTC to the current time in the timezone
            dateUTC = new Date(Date.now() + this.timezone.offsetUTC);
            dayNotSpecified = true;
            isToday = true;
        } else if (relativeDayParser.test(nluDate)) {
            //set dateUTC to the current time in the timezone, so we can offset it by our relative
            //days/months/years, etc
            dateUTC = new Date(Date.now() + this.timezone.offsetUTC);
            //check for a specific day in the format '#d', a number of days relative to today
            let regexResult = relativeDayParser.exec(nluDate);
            if (regexResult[2] === 'd') {
                let relativeDay = parseInt(regexResult[1], 10);
                if (relativeDay !== 0) {
                    dateUTC.setUTCDate(dateUTC.getUTCDate() + relativeDay);
                } else {
                    isToday = true;
                }
                this.timePeriod = timePeriods.DAY;
            } else if (regexResult[2] === 'wd') {
                //check for a weekend relative to now - 0wd should be the upcoming/current weekend,
                //1wd should be the weekend after that
                let numWeeksAhead = parseInt(regexResult[1], 10);
                //day of week would be 0-6, with 0 being sunday
                let dayOfWeek = dateUTC.getUTCDay();
                //add days until the end of the week (saturday) + number of weeks ahead
                let relativeDay = numWeeksAhead * 7 + (6 - dayOfWeek);
                //add exception for sunday
                // - for 'this weekend' is to report the weather for just sunday in that case, so
                //   the start day should be -1 to signify that it started yesterday
                // - for 'next weekend' on a sunday, the startDay should be 6, to get to saturday
                // - for 'last weekend' on a sunday, the startDay should be -8 to get to saturday a
                //   week ago
                if (dayOfWeek === 0) {
                    relativeDay -= 7;
                }
                if (relativeDay !== 0) {
                    dateUTC.setUTCDate(dateUTC.getUTCDate() + relativeDay);
                }
                this.durationDays = 2;
                this.timePeriod = timePeriods.WEEKEND;
            } else if (regexResult[2] === 'w') {
                //check for a week relative to today
                let numWeeksAhead = parseInt(regexResult[1], 10);
                let dayOfWeek = dateUTC.getUTCDay();
                //add 1 to start on monday
                // - sunday is dayOfWeek 0, so 'this week' on a sunday becomes +1 day, which
                //   is perfect for our purposes
                let relativeDay = numWeeksAhead * 7 - dayOfWeek + 1;
                if (relativeDay !== 0) {
                    dateUTC.setUTCDate(dateUTC.getUTCDate() + relativeDay);
                }
                this.durationDays = 7;
                this.timePeriod = timePeriods.WEEK;
            } else if (regexResult[2] === 'm') {
                //handle relative months, even though that's a little far out for things that we do
                let relativeMonth = parseInt(regexResult[1], 10);
                //set to the first of the month
                dateUTC.setUTCMonth(dateUTC.getUTCMonth() + relativeMonth, 1);
                //don't use duration days for months, because that is slightly complicated and silly
                //for all current Jibo purposes
                this.timePeriod = timePeriods.MONTH;
            } else if (regexResult[2] === 'y') {
                //handle relative years, even though that's very far out for what we do
                let relativeYear = parseInt(regexResult[1], 10) * 365;
                //set to January 1st of that year
                dateUTC.setUTCFullYear(dateUTC.getUTCFullYear() + relativeYear, 0, 1);
                //don't use duration days for months, because that is silly
                this.timePeriod = timePeriods.YEAR;
            }
        } else if (dateParser.test(nluDate)) {
            //day of month - factory currently doesn't tell us the month, so we'll assume that
            //we should use the current month
            dateUTC = new Date(Date.now() + this.timezone.offsetUTC);
            let date = parseInt(dateParser.exec(nluDate)[1], 10);
            //determine how many days are in the current month
            let daysInCurrentMonth = new Date(dateUTC.getUTCFullYear(), dateUTC.getUTCMonth() + 1, 0).getUTCDate();
            if (dateUTC.getUTCDate() < date && date <= daysInCurrentMonth) {
                dateUTC.setUTCDate(date);
            } else {
                //get this date for the next month because either it already passed this month
                //or the current month doesn't have enough days (asking for the 30th in Feb)
                //This still has some problems, as the next month might not have enough days
                //(asking for the 31st in Feb, March has 30 days)
                dateUTC.setUTCMonth(dateUTC.getUTCMonth() + 1);
                dateUTC.setUTCDate(date);
            }
            this.timePeriod = timePeriods.DAY;
        } else if (monthDateParser.test(nluDate)) {
            //parsing month + day of month - at least this will be more specific
            //in the absence of any direction to do things in the past, we will always get the next
            //year that a given month/day would happen
            let regexResult = monthDateParser.exec(nluDate);
            dateUTC = new Date(Date.now() + this.timezone.offsetUTC);
            let month = parseInt(regexResult[1], 10) - 1;//convert to Date's 0 based months
            let date = parseInt(regexResult[2], 10);
            let nowMonth = dateUTC.getUTCMonth();
            if (month < nowMonth || (month === nowMonth && date < dateUTC.getUTCDate())) {
                //increment year
                dateUTC.setUTCFullYear(dateUTC.getUTCFullYear() + 1);
            }
            dateUTC.setUTCMonth(month);
            dateUTC.setUTCDate(date);
            this.timePeriod = timePeriods.DAY;
        } else if (fullDateParser.test(nluDate)) {
            let regexResult = fullDateParser.exec(nluDate);
            //don't forget to convert month to Date's 0 based months
            dateUTC = new Date(Date.UTC(parseInt(regexResult[3], 10), parseInt(regexResult[1], 10) - 1, parseInt(regexResult[2], 10)));
            this.timePeriod = timePeriods.DAY;
        } else if (dayOfWeekParser.test(nluDate)) {
            //if specific day of the week, then determine the next time that will show up, unless
            //it refers to the last time that day showed up
            let regexResult = dayOfWeekParser.exec(nluDate);
            let dow = regexResult[1];
            dateUTC = new Date(Date.now() + this.timezone.offsetUTC);
            let relativeDay = DateTimeUtils.DAYS_OF_WEEK[dow] - dateUTC.getUTCDay();
            //if past day this week, bump it to next week
            if (relativeDay < 0) {
                relativeDay += 7;
            }
            //if input was for 'last <day>', then subtract 7. If factory changes to also handle
            //'next <day>' as '<day>_1w' then we should be able to handle it just fine
            //if it is '<day>_+1w' then we will need to change RegEx to account for that
            if (pastDOWParser.test(regexResult[2])) {
                regexResult = pastDOWParser.exec(regexResult[2]);
                let weeksDiff = parseInt(regexResult[1], 10);
                relativeDay += weeksDiff * 7;
            }
            if (relativeDay !== 0) {
                dateUTC.setUTCDate(dateUTC.getUTCDate() + relativeDay);
            } else {
                isToday = true;
            }
            this.timePeriod = timePeriods.DAY;
        } else if (monthNameParser.test(nluDate)) {
            //month by name
            let regexResult = monthNameParser.exec(nluDate);
            let monthNum = DateTimeUtils.MONTHS.indexOf(regexResult[1].toLowerCase());
            dateUTC = new Date(Date.now() + this.timezone.offsetUTC);
            //set to the first of that month, and if the month has gone by then make it next year
            if (monthNum < dateUTC.getUTCMonth()) {
                dateUTC.setUTCFullYear(dateUTC.getUTCFullYear() + 1, monthNum, 1);
            } else {
                dateUTC.setUTCMonth(monthNum, 1);
            }
            this.timePeriod = timePeriods.MONTH;
        } else if (yearParser.test(nluDate)) {
            //year by number, "2016", etc
            let regexResult = yearParser.exec(nluDate);
            //set to January 1st of that year
            dateUTC.setUTCFullYear(parseInt(regexResult[1], 10), 0, 1);
            this.timePeriod = timePeriods.YEAR;
        }
        // endregion date-parsing

        // region time-parsing
        //we don't deal with seconds and milliseconds for the purposes of DateTime

        if (!nluTime) {
            if (dayNotSpecified) {
                //time was set up as now, so we are leaving it alone
                this.timePeriod = timePeriods.NOW;
            } else {
                //clear hours and minutes, sec and ms, because the DateTime refers to the entire day
                dateUTC.setUTCHours(0, 0, 0, 0);
            }
        } else {
            //handle time periods that have standard names
            if (nluTime === 'noon') {
                dateUTC.setUTCHours(12, 0, 0, 0);
                this.timePeriod = timePeriods.HOUR;
            } else if (nluTime === 'midnight') {
                //midnight of the night that follows daytime
                // - this should adjust the date accordingly
                dateUTC.setUTCHours(24, 0, 0, 0);
                this.timePeriod = timePeriods.HOUR;
            } else if (nluTime === 'morning') {
                //morning: 6-11AM, inclusive
                dateUTC.setUTCHours(6, 0, 0, 0);
                this.durationHours = 5;
                this.timePeriod = timePeriods.MORNING;
            } else if (nluTime === 'afternoon') {
                //afternoon: 12-5PM, inclusive
                dateUTC.setUTCHours(12, 0, 0, 0);
                this.durationHours = 6;
                this.timePeriod = timePeriods.AFTERNOON;
            } else if (nluTime === 'evening') {
                //evening: 6-9PM, inclusive
                dateUTC.setUTCHours(18, 0, 0, 0);
                this.durationHours = 4;
                this.timePeriod = timePeriods.EVENING;
            } else if (nluTime === 'night') {
                //night: 10PM-4AM, inclusive
                dateUTC.setUTCHours(22, 0, 0, 0);
                this.durationHours = 7;
                this.timePeriod = timePeriods.NIGHT;
            } else if (timeParser.test(nluTime)){
                //split apart the time code (3:00, 10:00PM)
                let timeSplit = timeParser.exec(nluTime);
                //input is always in 12 hour time
                let hoursIn12H = parseInt(timeSplit[1], 10);
                let minutes = parseInt(timeSplit[2], 10);
                switch(timeSplit[3])
                {
                    case 'AM':
                        //check for 12 o'clock and convert it to 00:00
                        if (hoursIn12H === 12) {
                            dateUTC.setUTCHours(0);
                        } else {
                            dateUTC.setUTCHours(hoursIn12H);
                        }
                        break;
                    case 'PM':
                        if (hoursIn12H !== 12) {
                            dateUTC.setUTCHours(hoursIn12H + 12);
                        } else {
                            dateUTC.setUTCHours(hoursIn12H);
                        }
                        break;
                    default:
                        //if AM/PM not specified, attempt to pick the next correct time during
                        //waking hours
                        if (hoursIn12H === 12 || hoursIn12H < 6) {
                            //12AM - 5:59AM - sleeping hours for most people
                            // - skip these since AM not specified
                            let hoursIn24H = hoursIn12H === 12 ? hoursIn12H : hoursIn12H + 12;
                            //if day was not specified, then if the time is already passed
                            //do tomorrow at that time instead
                            if (dayNotSpecified) {
                                //nowHour is in 24 hour time
                                let nowHour = dateUTC.getUTCHours();
                                let nowMinutes = dateUTC.getUTCMinutes();
                                //if today, check to see if the time has passed already and move
                                //to the next one
                                if (nowHour > hoursIn24H ||
                                    (nowHour === hoursIn24H && nowMinutes >= minutes)) {
                                    dateUTC.setUTCDate(dateUTC.getUTCDate() + 1);
                                    dateUTC.setUTCHours(hoursIn24H);
                                } else {
                                    //if the time has not passed, then 24H time should be okay
                                    dateUTC.setUTCHours(hoursIn24H);
                                }
                            } else {
                                //if day was specified, then just set the time even if it is in
                                //the past
                                dateUTC.setUTCHours(hoursIn24H);
                            }
                        } else if (isToday) {
                            //if we are here, we have hours 6->11
                            //if today, determine if the target time has passed
                            let nowHour = dateUTC.getUTCHours();
                            let nowMinutes = dateUTC.getUTCMinutes();
                            if (nowHour < 12) {
                                //is currently morning, see if the 6-11 can still happen
                                //this morning
                                if (hoursIn12H > nowHour ||
                                    (hoursIn12H === nowHour && minutes > nowMinutes)) {
                                    //asked for time that is upcoming before noon
                                    //so everything is fine
                                    dateUTC.setUTCHours(hoursIn12H);
                                } else {
                                    //asked for time that has passed before noon, bump it to PM
                                    dateUTC.setUTCHours(hoursIn12H + 12);
                                }
                            } else {
                                //nowHour >= 12
                                let hoursIn24H = hoursIn12H === 12 ? hoursIn12H : hoursIn12H + 12;
                                if (hoursIn24H < nowHour ||
                                    (hoursIn24H === nowHour && minutes < nowMinutes)) {
                                    //asked for time that has passed after noon
                                    if (dayNotSpecified) {
                                        //if date was not specified, then move on to
                                        //tomorrow morning
                                        dateUTC.setUTCDate(dateUTC.getUTCDate() + 1);
                                        dateUTC.setUTCHours(hoursIn12H);
                                    } else {
                                        //otherwise, stick with the past time
                                        dateUTC.setUTCHours(hoursIn24H);
                                    }
                                } else {
                                    //asked for time that is upcoming before midnight
                                    dateUTC.setUTCHours(hoursIn24H);
                                }
                            }
                        } else {
                            //if we are here, we have hours 6->11
                            //not today, just set the time to AM and call it good
                            dateUTC.setUTCHours(hoursIn12H);
                        }
                }
                //set the minutes, clear seconds and milliseconds
                dateUTC.setUTCMinutes(minutes, 0, 0);
                this.timePeriod = minutes === 0 ? timePeriods.HOUR : timePeriods.MINUTE;
                // (end time code parsing here)
            } else if (relativeTimeParser.test(nluTime)) {
                //check for a relative time in the format '#h#m#s', a number of hours, minutes, and/or seconds
                let regexResult = relativeTimeParser.exec(nluTime);
                let relativeHours = parseInt(regexResult[2], 10);
                let relativeMinutes = parseInt(regexResult[3], 10);
                let relativeSeconds = parseInt(regexResult[4], 10);
                if (regexResult[1] === '-') {
                    relativeHours = -relativeHours;
                    relativeMinutes = -relativeMinutes;
                    relativeSeconds = -relativeSeconds;
                }
                if (relativeHours !== 0) {
                    dateUTC.setUTCHours(dateUTC.getUTCHours() + relativeHours);
                }
                if (relativeMinutes !== 0) {
                    dateUTC.setUTCMinutes(dateUTC.getUTCMinutes() + relativeMinutes);
                }
                if (relativeSeconds !== 0) {
                    dateUTC.setUTCSeconds(dateUTC.getUTCSeconds() + relativeSeconds);
                }
                this.timePeriod = timePeriods.MINUTE;
            }
        }
        // endregion time-parsing
        //now that we have parsed the date & time, get the actual UTC time and store it
        this.utc = dateUTC.getTime() - this.timezone.offsetUTC;
    }
}

export default DateTime;
