import axios from 'axios';
import crypto = require('crypto');
import LatLong from './LatLong';
import querystring = require('querystring');
import URLSafeBase64 = require('urlsafe-base64');

//Jibo owned API keys are supplied by Be/unit tests
let GOOGLE_API:string = null;
let WOLFRAM_API:string = null;

interface State {
    name:string;
    capital:string;
}

//BEGIN WOLFRAM RESULT TYPES
//Wolfram responses have other properties that we don't care about for this purpose
//pods are what they call their result groupings
interface WolframQueryResponse {
    pods: WolframPod[];
    success: boolean;
}
interface WolframPod {
    subpods: SubPod[];
    title: string;
}
interface SubPod {
    plaintext?: string; // plaintext comment or description
    title?: string; //title (sometimes empty string)
}
//END WOLFRAM RESULT TYPES

/**
 * @description Type of result LocationUtils.getCountryCapital
 * @typedef jibo.utils.LocationUtils~CapitalInfo
 * @prop {String} city - The name of the capital itself.
 * @prop {String} state - The state level location of the capital, if available.
 * @prop {String} country - The proper name of the country.
 * @private
 */
export type CapitalInfo = {
    city: string,
    state?: string,
    country?: string
};

