/**
 * @private
 */
export interface Bounds
{
    northeast: LatLong;
    southwest: LatLong;
}

/**
 * @private
 */
export interface Geometry
{
    bounds: Bounds;
    location_type: string;
    location: LatLong;
    viewport: Bounds;
}

/**
 * @private
 */
export interface GeoResult
{
    formatted_address: string;
    address_components: {long_name: string, short_name: string, types: string[]}[];
    geometry: Geometry;
    place_id: string;
    types: string[];
}

/**
 * State and capital
 * @class LocationUtils
 * @memberof jibo.utils
 * @intdocs
 */
export class LocationUtils {

    /**
     * Error given if no result was received from Wolfram Alpha
     * @name jibo.utils.LocationUtils#NO_RESULT_FROM_WA
     * @type {String}
     * @static
     * @private
     */
    static NO_RESULT_FROM_WA = 'No Result';

    /**
     * Error given if a result, but no valid result was received from Wolfram Alpha
     * @name jibo.utils.LocationUtils#NO_VALID_RESULTS_FROM_WA
     * @type {String}
     * @static
     * @private
     */
    static NO_VALID_RESULTS_FROM_WA = 'No Valid Results';

    /**
     * Sets the API key used for looking up country capitals
     * @method jibo.utils.LocationUtils.setCapitalLookupKey
     * @param  {String} key Key used to enable lookups with the correct credentials
     * @intdocs
     */
    static setCapitalLookupKey(key:string):void {
        WOLFRAM_API = key;
    }

    /**
     * Sets the API key used for looking up locations
     * @method jibo.utils.LocationUtils.setLocationLookupKey
     * @param  {String} key Key used to enable lookups with the correct credentials
     * @intdocs
     */
    static setLocationLookupKey(key:string):void {
        GOOGLE_API = key;
    }

    /**
     * Gets the full name of a US state from its two letter abbreviation.
     * @method jibo.utils.LocationUtils.getFullState
     * @param  {String} abbreviation The two letter US state abbreviation - LOWERCASE.
     * @return {String} The full state name, or an empty string if it is not a US state.
     * @intdocs
     */
    static getFullState(abbreviation:string):string {
        if (!US_STATES[abbreviation]) {
            return "";
        }
        return US_STATES[abbreviation].name;
    }

    /**
     * Gets the capital of a US state from is two letter abbreviation.
     * @method jibo.utils.LocationUtils.getUSStateCapital
     * @param  {String} abbreviation The two letter US state abbreviation - LOWERCASE.
     * @return {String} The state capital, or an empty string if it is not a US state.
     * @private
     */
    static getUSStateCapital(abbreviation:string):string {
        if (!US_STATES[abbreviation]) {
            return "";
        }
        return US_STATES[abbreviation].capital;
    }

    /**
     * Gets the capital of a country, including proper country name and potentially the state-level
     * region it is located in.
     * @method jibo.utils.LocationUtils.getCountryCapital
     * @param  {String} country The name of the country to look up
     * @return {Promise<utils.LocationUtils~CapitalInfo>} Promise to return the capital information.
     * @private
     */
    static getCountryCapital(country: string): Promise<CapitalInfo> {
        const qs = {
            input: country + ' capital',
            appid: WOLFRAM_API, //our api key
            output: "JSON",  //Output format
            podtitle: "Result", //Specifically interested in the "Result" pod
            scantimeout: 0.5//tell WA to not take long
        };

        let url = 'http://api.wolframalpha.com/v2/query?' + querystring.stringify(qs);

        return axios.get(url, {timeout: 8000})
        .then(response => {
            let results = response.data;
            if (!results) {
                throw new Error(LocationUtils.NO_RESULT_FROM_WA);
            }
            if (typeof results === 'string') {
                results = JSON.parse(results);
            }
            //For saving output from web
            /*
            console.groupCollapsed('WA: ', querystring.escape(url));
            console.log(JSON.stringify(results));
            console.groupEnd();
            */
            let queryResult:WolframQueryResponse = results.queryresult;

            //check to make sure we got a good result back
            //check whether wolfram deemed the query a success
            // if we didnt get a response from spokenResult, make sure there are some pods, then
            if (queryResult && queryResult.success && queryResult.pods) {
                // find the first 'primary' pod and get its plaintext result
                if (queryResult.pods[0] &&
                    queryResult.pods[0].subpods.length > 0 &&
                    queryResult.pods[0].title === "Result") {

                    const result = queryResult.pods[0].subpods[0].plaintext.split(',');

                    let output:CapitalInfo = {
                        city: result[0].trim()
                    };
                    //every result I've seen is at least "city, country"
                    if (result.length > 1) {
                        output.country = result[result.length - 1].trim();
                    }
                    //some results are "city, region, country"
                    if (result.length > 2) {
                        //get second to last, just in case we start getting more stuff
                        //in results
                        output.state = result[result.length - 2].trim();
                    }
                    return output;
                }
            }
            throw new Error(LocationUtils.NO_VALID_RESULTS_FROM_WA);
        });
    }

    /**
     * @private
     */
    static geocode(loc:string, callback:(err:Error, data:{results: GeoResult[]}) => void, opts?:{bounds?:string}): void {
        let endpoint = "/maps/api/geocode/json?";
        let options = Object.assign({sensor: false, address: loc, client:"gme-jiboinc", key:GOOGLE_API}, opts || {});
        options["signature"] = LocationUtils.generateGoogleSignature(GOOGLE_API, endpoint+querystring.stringify(options));
        let url = "https://maps.googleapis.com" + endpoint + querystring.stringify(options);
        axios.get(url)
        .then(resp => {
            //For saving output from web
            /*
            console.groupCollapsed('GEO: ', querystring.escape(url));
            console.log(JSON.stringify(body));
            console.groupEnd();
            */
            let result:{results: GeoResult[]};
            try {
                if (typeof resp.data === 'string') {
                    result = JSON.parse(resp.data);
                } else {
                    result = resp.data;
                }
            } catch (err) {
                callback(err, null);
                return;
            }
            callback(null, result);
        })
        .catch(err => callback(err, null));
    }

    /**
     * @private
     */
    static generateGoogleSignature(key:string, req:string):string {
        let privateKeyInBuffer = URLSafeBase64.decode(key);
        let hashInABuffer = crypto.createHmac('sha1', privateKeyInBuffer).update(req).digest();
        let hashEncodedWebSafe = URLSafeBase64.encode(hashInABuffer);
        return hashEncodedWebSafe;
    }
}
