import DateTime from './DateTime';

/**
 * Utilities for date and time.
 * @class DateTimeUtils
 * @memberof jibo.utils
 */
namespace DateTimeUtils {

    /**
     * Zero-based array of (lower-case) month names, starting with `january`.
     * @name jibo.utils.DateTimeUtils.MONTHS
     * @type {String[]}
     */
    export const MONTHS:string[] = [
        'january',
        'february',
        'march',
        'april',
        'may',
        'june',
        'july',
        'august',
        'september',
        'october',
        'november',
        'december'
    ];

    /**
     * Zero-based array of three-letter month abbreviations, starting with `Jan`.
     * @name jibo.utils.DateTimeUtils.MONTH_ABBREVIATIONS
     * @type {String[]}
     */
    export const MONTH_ABBREVIATIONS:string[] = [
        'Jan',
        'Feb',
        'Mar',
        'Apr',
        'May',
        'Jun',
        'Jul',
        'Aug',
        'Sep',
        'Oct',
        'Nov',
        'Dec'
    ];

    /**
     * Zero-based array of (lower-case) day names, starting with `sunday`.
     * @name jibo.utils.DateTimeUtils.DAYS_OF_WEEK
     * @type {String[]}
     */
    export const DAYS_OF_WEEK:string[] = [
        'sunday',
        'monday',
        'tuesday',
        'wednesday',
        'thursday',
        'friday',
        'saturday'
    ];

    /**
     * Milliseconds per day.
     * @name jibo.utils.DateTimeUtils.MS_PER_DAY
     * @type {Number}
     * @private
     */
    export const MS_PER_DAY:number = 1000 * 60 * 60 * 24;
    
    /**
     * Unit of time for getting the difference between two DateTimes
     * @typedef jibo.utils.DateTimeUtils.DiffUnit
     * @prop Milliseconds 0
     * @prop Seconds 1
     * @prop Minutes 2
     * @prop Hours 3
     * @prop Days 4
     * @prop Weeks 5
     */
    export enum DiffUnit {
        Milliseconds = 0,
        Seconds,
        Minutes,
        Hours,
        Days,
        Weeks
    }

    /**
     * Gets a verbal/written string of an integer value. Currently this function can only handle values
     * between `-99` and `99`.
     * @method jibo.utils.DateTimeUtils.getVerbalNumber
     * @param {Number} input Integer to convert.
     * @returns {String} Spoken version of the number.
     */
    export function getVerbalNumber(input:number):string {
        if (input === 0) {
            return 'zero';
        }
        let returnVal = input < 0 ? 'negative ' : '';
        input = Math.abs(input);
        //enforce that these values are integers with binary OR: '| 0';
        let tens = input / 10 | 0;
        let ones = input % 10 | 0;
        switch(tens) {
            case 1:
                switch(ones) {
                    case 0:
                        returnVal += 'ten';
                        break;
                    case 1:
                        returnVal += 'eleven';
                        break;
                    case 2:
                        returnVal += 'twelve';
                        break;
                    case 3:
                        returnVal += 'thirteen';
                        break;
                    case 4:
                        returnVal += 'fourteen';
                        break;
                    case 5:
                        returnVal += 'fifteen';
                        break;
                    case 6:
                        returnVal += 'sixteen';
                        break;
                    case 7:
                        returnVal += 'seventeen';
                        break;
                    case 8:
                        returnVal += 'eighteen';
                        break;
                    case 9:
                        returnVal += 'nineteen';
                        break;
                }
                break;
            case 2:
                returnVal += 'twenty';
                break;
            case 3:
                returnVal += 'thirty';
                break;
            case 4:
                returnVal += 'forty';
                break;
            case 5:
                returnVal += 'fifty';
                break;
            case 6:
                returnVal += 'sixty';
                break;
            case 7:
                returnVal += 'seventy';
                break;
            case 8:
                returnVal += 'eighty';
                break;
            case 9:
                returnVal += 'ninety';
                break;
        }
        if (tens !== 1)
        {
            if (tens !== 0 && ones !== 0) {
                returnVal += ' ';
            }
            switch(ones) {
                case 1:
                    returnVal += 'one';
                    break;
                case 2:
                    returnVal += 'two';
                    break;
                case 3:
                    returnVal += 'three';
                    break;
                case 4:
                    returnVal += 'four';
                    break;
                case 5:
                    returnVal += 'five';
                    break;
                case 6:
                    returnVal += 'six';
                    break;
                case 7:
                    returnVal += 'seven';
                    break;
                case 8:
                    returnVal += 'eight';
                    break;
                case 9:
                    returnVal += 'nine';
                    break;
            }
        }
        return returnVal;
    }

    /**
     * Gets the [ordinal form]{@link https://en.wiktionary.org/wiki/ordinal_number} of a positive integer.
     * @method jibo.utils.DateTimeUtils.getOrdinal
     * @param  {Number} num Integer to get the ordinal form of.
     * @return {String} Ordinal number.
     */
    export function getOrdinal(num:number):string {
        if (num === 0) {
            return 'zero';
        }
        if (num < 20 && num > 10) {
            return String(num) + 'th';
        }
        switch(num % 10) {
            case 1:
                return String(num) + 'st';
            case 2:
                return String(num) + 'nd';
            case 3:
                return String(num) + 'rd';
            default:
                return String(num) + 'th';
        }
    }

    /**
     * Gets a verbal string for Jibo to read from a time in 24-hour values.
     * @method jibo.utils.DateTimeUtils.getVerbalTime
     * @param {Number} hour Hour in 24-hour time.
     * @param {Number} [minute=0] Minutes in the time.
     * @param {Boolean} [dropPeriod=false] `true` if the period (AM/PM) should be dropped from the time.
     * @returns {String} Verbal time, ie `three PM`.
     */
    export function getVerbalTime(hour:number, minute:number = 0, dropPeriod:boolean = false):string {
        if (dropPeriod) {
            if (hour >= 12) {
                if (hour > 12) {
                    hour -= 12;
                }
            } else if (hour === 0) {
                hour = 12;
            }
            let time = getVerbalNumber(hour) + ' ';
            if (minute === 0) {
                time += 'oh clock';
            } else if (minute < 10) {
                time += 'oh ' + getVerbalNumber(minute);
            } else {
                time += getVerbalNumber(minute);
            }
            return time;
        } else {
            return getVisualTime(hour, minute);
        }
    }

    /**
     * Gets a string suitable for visual display of a time.
     * @method jibo.utils.DateTimeUtils.getVisualTime
     * @param {Number} hour The hour in 24-hour time.
     * @param {Number|null} [minute=0] Minutes in the time. Pass null to drop minutes entirely (`3 PM`).
     * @param {Boolean} [dropPeriod=false] `true` if the period (AM/PM) should be dropped from the time.
     * @returns {String} Visual time, ie `3:00 PM`.
     */
    export function getVisualTime(hour:number, minute?:number, dropPeriod:boolean = false) {
        let period = 'AM';
        if (hour >= 12) {
            period = 'PM';
            if (hour > 12) {
                hour -= 12;
            }
        } else if (hour === 0) {
            hour = 12;
        }
        let minuteName = '';
        if (minute !== null) {//specifically pass null to drop the minutes?
            minuteName = ':';
            minute = minute || 0;
            if (minute < 10) {
                minuteName += '0';
            }
            minuteName += minute;
        }
        let hourName = String(hour === 0 ? 12 : hour);
        if (dropPeriod) {
            return `${hourName}${minuteName}`;
        }
        return `${hourName}${minuteName} ${period}`;
    }

    /**
     * Converts a 24-hour HHMM time string to a verbal 12-hour time for Jibo to read.
     * @method jibo.utils.DateTimeUtils.getVerbalTimeFrom24Hour
     * @param {String} time 24-hour time as a string, ie `1500`.
     * @returns {String} Verbal time, ie `three PM`.
     */
    export function getVerbalTimeFrom24Hour(time:string):string {
        return getVerbalTime(
            parseInt(time.substr(0, 2), 10),
            parseInt(time.substr(2, 2), 10)
        );
    }

    /**
     * Converts a 24-hour HHMM time string to 12-hour time for display.
     * @method jibo.utils.DateTimeUtils.getVisualTimeFrom24Hour
     * @param {String} time 24 hour time as a string, ie `1500`.
     * @returns {String} Visual time, ie `3:00 PM`.
     */
    export function getVisualTimeFrom24Hour(time:string):string {
        return getVisualTime(
            parseInt(time.substr(0, 2), 10),
            parseInt(time.substr(2, 2), 10)
        );
    }

    /**
     * Gets the number of days between two dates, ignoring hours and minutes.
     * @method jibo.utils.DateTimeUtils.getDaysBetweenDates
     * @param {Date} a Earlier date.
     * @param {Date} b Later date.
     * @returns {Number} The number of days between the two dates.
     */
    export function getDaysBetweenDates(a, b):number {
      // Discard the time and time-zone information.
      const utc1 = Date.UTC(a.getUTCFullYear(), a.getUTCMonth(), a.getUTCDate());
      const utc2 = Date.UTC(b.getUTCFullYear(), b.getUTCMonth(), b.getUTCDate());

      //adding 0.1 because I am afraid of floating point errors combined with Math.floor()
      return Math.floor((utc2 - utc1) / this.MS_PER_DAY + 0.1);
    }
    
    /**
     * Gets the amount of time between two DateTimes. Differences are not rounded. When getting
     * the difference in days, this is not the difference in dates, but the difference in 24 hour
     * segments.
     * @method jibo.utils.DateTimeUtils.diffDateTimes
     * @param {jibo.utils.DateTime} a Earlier date.
     * @param {jibo.utils.DateTime} b Later date.
     * @param {jibo.utils.DateTimeUtils.DiffUnit} [unit=DiffUnit.Milliseconds] Unit to get the difference in.
     * @returns {Number} The difference between the two dates.
     */
    export function diffDateTimes(a:DateTime, b:DateTime, unit:DiffUnit = DiffUnit.Milliseconds):number {
        let diff = b.utc - a.utc;
        //go through all the units, dividing for each one
        if (unit > DiffUnit.Milliseconds) {
            //past ms, upgrade to seconds
            diff /= 1000;
        }
        if (unit > DiffUnit.Seconds) {
            //past seconds, upgrade to minutes
            diff /= 60;
        }
        if (unit > DiffUnit.Minutes) {
            //past minutes, upgrade to hours
            diff /= 60;
        }
        if (unit > DiffUnit.Hours) {
            //past hours, upgrade to days
            diff /= 24;
        }
        if (unit > DiffUnit.Days) {
            //past days, upgrade to weeks
            diff /= 7;
        }
        return diff;
    }
}

export default DateTimeUtils;
