import {LocationUtils} from './LocationUtils';
import LatLong from './LatLong';
import Timezone, {TimezoneJSON} from './Timezone';
import { Log } from 'jibo-log';


let log:Log = new Log('Location');

/**
 * @private
 */
export function initLog(parentLog:Log) {
    log = parentLog.createChild('Location');
}

//multiplier conversion from miles to radians, on Earth
const MILES_TO_RADIANS = 1 / 3959;//http://stackoverflow.com/a/3880410
//get a square of BOUNDS_RADIUS*2 per side to sort of prioritize locations in that many miles
const BOUNDS_RADIUS = 100 * MILES_TO_RADIANS;
const RADS_TO_DEGREES = 180 / Math.PI;
const DEGREES_TO_RADS = Math.PI / 180;

//from http://gis.stackexchange.com/a/5822
function moveLatLong(inLat:number, inLng:number, distRadians:number, angleRadians:number):LatLong {
    inLat *= DEGREES_TO_RADS;
    inLng *= DEGREES_TO_RADS;
    let PI = Math.PI;
    let lat = Math.asin(Math.sin(inLat) * Math.cos(distRadians) + Math.cos(inLat) * Math.sin(distRadians) * Math.cos(angleRadians));
    let lng;
    if (Math.cos(lat) === 0) {
        // endpoint a pole
        lng = inLng;
    } else {
        //calculate the longitude from the new latitude
        lng = (inLng - Math.asin(Math.sin(angleRadians) * Math.sin(distRadians) / Math.cos(lat)) + PI) % (2 * PI) - PI;
    }
    return {lat:lat * RADS_TO_DEGREES, lng: lng * RADS_TO_DEGREES};
}

//capitalizes the first letter of each word and lowercases the rest of the word
function toTitleCase(str:string) {
    return str.replace(/\w\S*/g, function(txt){return txt.charAt(0).toUpperCase() + txt.substr(1).toLowerCase();});
}

function areStringsEqual(strA, strB) {
    //ensure that both strings exist before attempting to convert to lowercase
    if (strA && !strB) {
        return false;
    }
    if (strB && !strA) {
        return false;
    }
    if (!strA && !strB) {
        return true;
    }
    return strA.toLowerCase() === strB.toLowerCase();
}

let JIBO_HOME:Location = null;//set after we define the class


/**
 * @interface jibo.utils~LocationJSON
 * @prop _type 'Location'
 * @prop [city] {string}
 * @prop [state] {string}
 * @prop [stateAbbr] {string}
 * @prop [country] {string}
 * @prop [countryCode] {string}
 * @prop lat {number}
 * @prop lng {number}
 * @prop [timezone] {jibo.utils~TimezoneJSON}
 */
export interface LocationJSON {
    __type: 'Location';
    city?:string;
    state?:string;
    stateAbbr?:string;
    country?:string;
    countryCode?:string;
    lat:number;
    lng:number;
    timezone?: TimezoneJSON;
}

/**
 * Class for handling locations - taking NLU inputs and turning them into full locations with
 * a latitude and longitude, and optionally an attached timezone.
 * @class Location
 * @memberof jibo.utils
 * @param {String} [city] The city for the location.
 * @param {String} [state] The US state abbreviation for the location.
 * @param {String} [country] The country for the location.
 * @intdocs
 */
//internal for now, because we don't want to expose customer locations willy nilly
export default class Location {
    /**
     * The city name.
     * @name jibo.utils.Location#city
     * @type {String}
     */
    public city:string;
    /**
     * The state (or political equivalent) abbreviation, using the ISO_3166 1 alpha 2 spec (as best as Google gives it to us)
     * @name jibo.utils.Location#stateAbbr
     * @type {String}
     */
    public stateAbbr:string;
    /**
     * The state (or political equivalent) name.
     * @name jibo.utils.Location#state
     * @type {String}
     */
    public state:string;
    /**
     * The country name.
     * @name jibo.utils.Location#country
     * @type {String}
     */
    public country:string;
    /**
     * The country code, using the ISO_3166 1 alpha 2 spec (as best as Google gives it to us)
     * @name jibo.utils.Location#countryCode
     * @type {String}
     */
    public countryCode:string;
    /**
     * `true` if this location should make sure it has a timezone before returning from `fetch()`.
     * @name jibo.utils.Location#needsTimezone
     * @type {Boolean}
     */
    public needsTimezone:boolean;
    /**
     * The timezone that this location resides in.
     * @name jibo.utils.Location#timezone
     * @type {jibo.utils.Timezone}
     */
    public timezone:Timezone;
    /**
     * The latitude of this location. Negative values reflect latitudes south of the equator.
     * @name jibo.utils.Location#lat
     * @type {Number}
     */
    public lat:number;
    /**
     * The longitude of this location. Negative values reflect longitudes west of the Prime Meridian.
     * @name jibo.utils.Location#lng
     * @type {Number}
     */
    public lng:number;
    /**
     * Latitude and longitude boundary for providing to the geocoding service to prefer locations
     * near Jibo's.
     * @name jibo.utils.Location#latLongBounds
     * @type {Object}
     * @private
     */
    private latLongBounds: {north:number, east:number, west:number, south:number};
    /**
     * Calculated region array, to avoid recalculating them when the location doesn't change.
     * @name jibo.utils.Location#calculatedRegions
     * @type {String[]}
     * @private
     */
    private calculatedRegions: string[];

    /**
     * Creates and returns a Location object. If no city, state, or country was supplied, returns
     * Jibo's home location. All parameters are expected to be from the NLU parsing.
     * @method jibo.utils.Location#create
     * @param {String} [city] The city for the location.
     * @param {String} [state] The US state abbreviation for the location.
     * @param {String} [country] The country for the location.
     * @static
     */
    public static create(city?:string, state?:string, country?:string):Location {
        //sanitize NLU inputs
        if (city === 'null') {
            city = null;
        }
        if (state === 'null') {
            state = null;
        }
        if (country === 'null') {
            country = null;
        }
        if (!city && !state && !country) {
            return JIBO_HOME;
        }
        return new Location(city, state, country);
    }

    constructor(city?:string, state?:string, country?:string) {
        //sanitize NLU inputs
        if (city === 'null') {
            city = null;
        }
        if (state === 'null') {
            state = null;
        }
        if (country === 'null') {
            country = null;
        }
        this.city = city;
        this.stateAbbr = state;
        this.state = null;
        this.country = country;
        this.countryCode = null;
        //if state in the US, but not city, get state capital
        if (!city && state) {
            this.city = LocationUtils.getUSStateCapital(state);
        }
        //By default, Locations do not look up the timezone. If you set needsTimezone to true,
        //it will look up the timezone as part of fetch().
        this.needsTimezone = false;
        this.timezone = null;
        //latitude in minutes
        this.lat = null;
        //longitude in minutes
        this.lng = null;
        //a cached boundary object for getting nearby locations
        this.latLongBounds = null;
        this.calculatedRegions = null;
    }

    /**
     * Jibo's home location
     * @name jibo.utils.Location#jiboHome
     * @type {Location}
     * @static
     * @readOnly
     */
    public static get jiboHome():Location {
        return JIBO_HOME;
    }

    /**
     * `true` if this location is the same as Jibo's home.
     * @name jibo.utils.Location#isLocal
     * @type {Boolean}
     * @readOnly
     */
    public get isLocal() {
        return this.equals(JIBO_HOME);
    }

    /**
     * Completes missing location data and gets latitude and longitude.
     * If `needsTimezone=true`, also gets the timezone. The callback takes `(error, {lat, lng})`.
     * @method jibo.utils.Location#fetch
     * @param  {Function} callback The function to be called when the location has been fetched.
     * @param  {Boolean} [skipWA] `true` if a Wolfram Alpha query should be skipped. WA is only used to look up country capitals.
     */
    public fetch(callback:(error:any, latLng:LatLong)=>void, skipWA:boolean = false) {
        if (this.lat !== null && this.lng !== null) {
            let ll = { lat: this.lat, lng: this.lng };
            if (this.needsTimezone && !this.timezone) {
                this.timezone = new Timezone();
                this.timezone.fetch(ll, (/*error, result*/) => {
                    callback(null, ll);
                });
            } else {
                callback(null, ll);
            }
        } else {
            //special handling for country only requests
            if (!skipWA && !this.city && !this.stateAbbr && this.country) {
                //use WA to look up capital
                LocationUtils.getCountryCapital(this.country)
                    .then((data) => {
                        //use the full data
                        this.city = data.city;
                        this.state = data.state;
                        this.country = data.country || this.country;
                        log.debug('Got capital from WA');
                        //now do the proper fetching
                        this.fetch(callback);
                    })
                    .catch((e) => {
                        //not a huge deal, so just have Google do the best it can with just
                        //the country
                        if (e !== LocationUtils.NO_VALID_RESULTS_FROM_WA) {
                            log.warn('Error looking up capital', e);
                        } else {
                            log.debug('WA did not get us a capital');
                        }
                        this.fetch(callback, true);
                    });
                return;
            }
            let city = this.city;
            //set up the address so that it can be 'city, state', or just 'city', or even 'country'
            let address = [city, this.stateAbbr, this.country]
                .filter((n) => {return !!n;})
                .join(', ');
            let opts;
            //options for including bounds - https://developers.google.com/maps/documentation/javascript/geocoding#GeocodingViewports
            let bounds = JIBO_HOME.getLatLongBounds();
            if (bounds) {
                opts = {bounds: `${bounds.south.toFixed(12)},${bounds.west.toFixed(12)}|${bounds.north.toFixed(12)},${bounds.east.toFixed(12)}`};
            }
            LocationUtils.geocode(address, (err, data) => {
                if (err) {
                    log.warn('Error when geocoding: ', err);
                    callback(err, null);
                    return;
                }

                if (!data || !data.results || !data.results.length || !data.results[0].geometry ||
                    !data.results[0].geometry.location) {
                    let message = 'Bad geocode results: ';
                    const jsonData = JSON.stringify(data);
                    if (!data) {
                        message += 'no data';
                    } else if (!data.results) {
                        message += 'data does not have results - ' + jsonData;
                    } else if (!data.results.length) {
                        message += 'results is empty - ' + jsonData;
                    } else if (!data.results[0].geometry) {
                        message += 'first result has no geometry - ' + jsonData;
                    } else if (!data.results[0].geometry.location) {
                        message += 'first result has no location - ' + jsonData;
                    }
                    log.warn(`On search for ${address}`, message);
                    callback(message, null);
                    return;
                } else {
                    //get the first political result - no natural features
                    //also ensure that it is a city or neighborhood, if we asked for a city
                    let result = null;
                    for (let i = 0; i < data.results.length; ++i) {
                        let types = data.results[i].types;
                        if (types.indexOf('political') >= 0 &&
                            (!this.city || types.indexOf('locality') >= 0 ||
                                types.indexOf('sublocality') >= 0)) {
                            result = data.results[i];
                            break;
                        }
                    }
                    //if we asked for a city and not a state, and don't have a result, then
                    //check again for a state level result - this should allow us to handle stuff
                    //like Tokyo, Japan. Tokyo is a Prefecture, but everyone refers to it as a city
                    if (!result && this.city) {
                        for (let i = 0; i < data.results.length; ++i) {
                            let types = data.results[i].address_components[0].types;
                            if (types.indexOf('political') >= 0 &&
                                (types.indexOf('administrative_area_level_1') >= 0 ||
                                types.indexOf('administrative_area_level_2') >= 0)) {
                                result = data.results[i];
                                break;
                            }
                        }
                    }
                    //if we couldn't find a valid result, error hard
                    if (!result) {
                        log.warn('No valid location found: ', data);
                        callback('no valid location found - ' + JSON.stringify(data), null);
                        return;
                    }

                    let location = result.geometry.location;
                    this.lat = location.lat;
                    this.lng = location.lng;

                    //Go through results to pick up missing information, like state/country
                    let components = result.address_components;
                    let foundCity:string = null;
                    let foundState:string = null;
                    let foundStateAbbr:string = null;
                    let foundCountry:string = null;
                    let foundCountryCode:string = null;

                    //count down to ensure that we get sublocality over locality
                    for (let i = components.length - 1; i >= 0; --i) {
                        let comp = components[i];
                        if (comp.types.indexOf('locality') >= 0 ||
                            comp.types.indexOf('sublocality') >= 0) {
                            foundCity = comp.long_name;
                        }
                        // this is for Brasilia (technically a county (sort of))
                        if (comp.types.indexOf('administrative_area_level_2') >= 0 && !foundCity) {
                            foundCity = comp.long_name;
                        }
                        //result.address_components[n].types[0] == 'administrative_area_level_1' for a state
                        if (comp.types.indexOf('administrative_area_level_1') >= 0) {
                            foundState = comp.long_name;
                            foundStateAbbr = comp.short_name.toLowerCase();
                        }
                        //result.address_components[n].types[0] == 'country' for a country
                        if (comp.types.indexOf('country') >= 0) {
                            foundCountryCode = comp.short_name;
                            if (foundCountryCode === 'US') {
                                foundCountry = 'usa';
                            } else {
                                foundCountry = comp.long_name.toLowerCase();
                            }
                        }
                    }
                    this.city = foundCity;
                    this.stateAbbr = foundStateAbbr;
                    if (foundCountryCode === 'US') {
                        this.state = LocationUtils.getFullState(this.stateAbbr) || foundState;
                    } else {
                        this.state = foundState;
                    }
                    //generally, we should use Google's proper country name, but sometimes
                    // it doesn't have country data in the result (Pristina, Kosovo), so we need to
                    //keep the result that we have in that case
                    if (foundCountry) {
                        this.country = foundCountry;
                        this.countryCode = foundCountryCode;
                    }

                    if (this.needsTimezone && !this.timezone) {
                        this.timezone = new Timezone();
                        this.timezone.fetch(location, (/*error, result*/) => {
                            callback(null, location);
                        });
                    } else {
                        callback(null, location);
                    }
                }
            }, opts);
        }
    }

    /**
     * Checks to see if this location is in a given region, by comparing to countryCode or calculated regions (stateAbbr is combined with countryCode).
     * @method jibo.utils.Location#isInRegion
     * @param  {string|string[]} regions The region or regions to compare to
     * @return {Boolean} `true` if this location is in one of the compared regions
     */
    public isInRegion(regions:string|string[]):boolean {
        if (!this.calculatedRegions) {
            this.calculatedRegions = this.calculateRegions();
        }
        if (typeof regions === 'string') {
            return this.calculatedRegions.indexOf(regions) > -1;
        }
        for (let i = 0, length = regions.length; i < length; ++i) {
            if (this.calculatedRegions.indexOf(regions[i]) > -1) {
                return true;
            }
        }
        return false;
    }

    /**
     * Compares two Locations, by city, stateAbbr, and country.
     * @method jibo.utils.Location#equals
     * @param  {Location} loc The Location to compare to this one.
     * @return {Boolean} `true` if the two locations are the same
     */
    public equals(loc) {
        if (this === loc) {
            return true;
        }
        return (areStringsEqual(this.city, loc.city) &&
            areStringsEqual(this.stateAbbr, loc.stateAbbr) &&
            areStringsEqual(this.country, loc.country));
    }

    /**
     * Gets the location name in a format suitable for insertion into TTS. If the location is local
     * returns an empty string.
     * @method jibo.utils.Location#getStandardName
     * @return {String} The location name.
     */
    public getStandardName() {
        let rtn = '';
        //return an empty string if this is local, or we are returning nothing
        if (this.equals(JIBO_HOME)) {
            return rtn;
        }
        if (this.city) {
            rtn += this.city;
        }
        //use state if in the same country, or in the US
        if (this.state && (!this.city || this.countryCode === JIBO_HOME.countryCode || this.countryCode === 'US')) {
            if (rtn.length) {
                rtn += ' ';
            }
            rtn += this.state;
        }
        //drop country if it is the same one as Jibo's home, or in the US, due to states being statey
        if (this.country && (this.countryCode !== JIBO_HOME.countryCode && this.countryCode !== 'US')) {
            if (rtn.length) {
                rtn += ' ';
            }
            if (this.countryCode === 'US') {
                rtn += 'U.S.A.';
            } else {
                rtn += this.country;
            }
        }
        return rtn;
    }

    /**
     * Gets the location name in a format suitable for insertion into TTS, but prefixed with "In ".
     * If the location is local returns an empty string.
     * @method jibo.utils.Location#prefixIn
     * @return {String} The location name.
     */
    public prefixIn() {
        //return an empty string if this is local, or we are returning nothing
        if (this.equals(JIBO_HOME)) {
            return '';
        }
        return 'In ' + this.getStandardName();
    }

    /**
     * Gets the location name in a format suitable for visual display. US states are abbreviated.
     * If in the same country as Jibo, the state will be used instead of the country. If in a
     * different country, the state will be dropped.
     * @method jibo.utils.Location#toString
     * @return {String} The location name.
     */
    public toString() {
        let rtn = '';
        if (this.city) {
            rtn += toTitleCase(this.city);
        }
        if (this.state && (!this.city || this.countryCode === JIBO_HOME.countryCode)) {
            if (rtn.length) {
                rtn += ', ';
            }
            rtn += this.countryCode === 'US' && this.stateAbbr ? this.stateAbbr.toUpperCase() : this.state;
        }
        //drop country if it is the same one as Jibo's home
        if (this.country && this.countryCode !== JIBO_HOME.countryCode) {
            if (rtn.length) {
                rtn += ', ';
            }
            if (this.countryCode === 'US') {
                rtn += 'USA';
            } else {
                rtn += toTitleCase(this.country);
            }
        }
        return rtn;
    }

    /**
     * To be called by logging methods to have a more useful output.
     * MIMs will call this if it is in the MIM prompt data.
     * @method jibo.utils.Location#toLog
     */
    public toLog() {
        //not including if this location is Jibo's home, because that would probably be bad
        return `[Location: ${this.toString()}]`;
    }

    toJSON(): LocationJSON {
        return {
            __type: 'Location',
            city: this.city,
            state: this.state,
            stateAbbr: this.stateAbbr,
            country: this.country,
            countryCode: this.countryCode,
            lat: this.lat,
            lng: this.lng,
            timezone: this.timezone ? this.timezone.toJSON() : null
        };
    }

    /**
     * Gets a square for giving to Google to adjust the location results for partial requests
     * @method jibo.utils.Location#getLatLongBounds
     * @private
     */
    private getLatLongBounds() {
        //use stored value if we have one
        if (this.latLongBounds) {
            return this.latLongBounds;
        }
        if (this.lat === null || this.lng === null) {
            return null;
        }

        this.latLongBounds = {north:0, east:0, west:0, south:0};
        //get north side
        let tempLL = moveLatLong(this.lat, this.lng, BOUNDS_RADIUS, 0);
        this.latLongBounds.north = tempLL.lat;
        //get west side
        tempLL = moveLatLong(this.lat, this.lng, BOUNDS_RADIUS, Math.PI / 2);
        this.latLongBounds.west = tempLL.lng;
        //get south side
        tempLL = moveLatLong(this.lat, this.lng, BOUNDS_RADIUS, Math.PI);
        this.latLongBounds.south = tempLL.lat;
        //get east side
        tempLL = moveLatLong(this.lat, this.lng, BOUNDS_RADIUS, Math.PI * 1.5);
        this.latLongBounds.east = tempLL.lng;

        return this.latLongBounds;
    }

    private calculateRegions():string[] {
        const output:string[] = [];
        if (this.countryCode) {
            //include country
            output.push(this.countryCode.toUpperCase());
            //include state, if available, in full format because state codes are only unique to country
            if (this.stateAbbr) {
                output.push(`${this.countryCode.toUpperCase()}-${this.stateAbbr.toUpperCase()}`);
            }
        }
        //all done region-wise for now
        return output;
    }
}

//Default for testing/having a value
JIBO_HOME = new Location();
JIBO_HOME.city = 'boston';
JIBO_HOME.stateAbbr = 'ma';
JIBO_HOME.state = 'Massachusetts';
JIBO_HOME.country = 'usa';
JIBO_HOME.countryCode = 'US';
JIBO_HOME.lat = 42.313352;
JIBO_HOME.lng = -71.1273681;
//timezone for EST from Nov -> March (DST on)
JIBO_HOME.timezone = new Timezone({
    offsetUTC: -18000000,
    name: "Eastern Standard Time",
    id: "America/New_York",
    __type: "Timezone"
});

//only used once, by jibo module to set home
export function setHome(home:Location) {
    JIBO_HOME = home;
}
